    int L,n,cnt=0,sum=0;
    cin>>L>>n;
    for(int i=1; i<=n; i++) {
        int x;
        bool flag = false;
        cin>>x;
        for(int j=1; j<x; j++) {
            if(__①__) {
                flag = true;
                break;
            }
        }

        if(flag == true) {
            if(__②__) {
                sum +=x;
                cnt++;
            } else {
                __③__
            }
        }
    }
    cout<<cnt;
    return 0;
}
```
